"""Pydantic — Data validation using Python type annotations."""
from __future__ import annotations

import json
from typing import Any, ClassVar, Dict, Generator, Iterator, List, Optional, Set, Tuple, Type, Union


class ModelMetaclass(type):
    """Metaclass for BaseModel that processes field definitions."""

    def __new__(mcs, name: str, bases: tuple, namespace: dict, **kwargs: Any) -> type:
        fields: Dict[str, Any] = {}
        annotations = namespace.get("__annotations__", {})
        for field_name, field_type in annotations.items():
            if field_name.startswith("_"):
                continue
            default = namespace.get(field_name, ...)
            fields[field_name] = {"type": field_type, "default": default}
        namespace["__fields__"] = fields
        namespace["model_fields"] = fields
        return super().__new__(mcs, name, bases, namespace)


class BaseModel(metaclass=ModelMetaclass):
    """
    Base class for all Pydantic models.

    Usage::

        from pydantic import BaseModel

        class User(BaseModel):
            id: int
            name: str
            email: str

        user = User(id=1, name="Ana", email="ana@example.com")
        print(user.model_dump())
        # {'id': 1, 'name': 'Ana', 'email': 'ana@example.com'}
    """

    model_config: ClassVar[Dict[str, Any]] = {}
    __fields__: ClassVar[Dict[str, Any]] = {}
    model_fields: ClassVar[Dict[str, Any]] = {}

    def __init__(self, **data: Any) -> None:
        for key, value in data.items():
            object.__setattr__(self, key, value)

    def model_dump(
        self,
        *,
        mode: str = "python",
        include: Optional[Set[str]] = None,
        exclude: Optional[Set[str]] = None,
        by_alias: bool = False,
        exclude_none: bool = False,
        exclude_defaults: bool = False,
        exclude_unset: bool = False,
        round_trip: bool = False,
    ) -> Dict[str, Any]:
        """Serialize model to dict."""
        result = {}
        for key in self.__fields__:
            value = getattr(self, key, None)
            if exclude and key in exclude:
                continue
            if include and key not in include:
                continue
            if exclude_none and value is None:
                continue
            result[key] = value
        return result

    def model_dump_json(self, **kwargs: Any) -> str:
        """Serialize model to JSON string."""
        return json.dumps(self.model_dump(**kwargs))

    @classmethod
    def model_validate(cls, obj: Any, *, strict: bool = False, from_attributes: bool = False) -> "BaseModel":
        """Validate and create model from dict or ORM object."""
        if from_attributes or cls.model_config.get("from_attributes"):
            data = {key: getattr(obj, key) for key in cls.__fields__}
        elif isinstance(obj, dict):
            data = obj
        else:
            raise ValueError(f"Cannot validate {type(obj)}")
        return cls(**data)

    @classmethod
    def model_json_schema(cls, *, mode: str = "validation") -> Dict[str, Any]:
        """Generate JSON Schema for this model."""
        properties = {}
        for field_name, field_info in cls.__fields__.items():
            properties[field_name] = {"type": "string"}  # simplified
        return {
            "type": "object",
            "title": cls.__name__,
            "properties": properties,
        }

    def __repr__(self) -> str:
        fields = ", ".join(f"{k}={getattr(self, k, None)!r}" for k in self.__fields__)
        return f"{self.__class__.__name__}({fields})"


class Field:
    """Pydantic field with metadata."""

    def __init__(
        self,
        default: Any = ...,
        *,
        alias: Optional[str] = None,
        title: Optional[str] = None,
        description: Optional[str] = None,
        gt: Optional[float] = None,
        ge: Optional[float] = None,
        lt: Optional[float] = None,
        le: Optional[float] = None,
        min_length: Optional[int] = None,
        max_length: Optional[int] = None,
        pattern: Optional[str] = None,
        examples: Optional[List[Any]] = None,
    ) -> None:
        self.default = default
        self.alias = alias
        self.title = title
        self.description = description
        self.metadata: Dict[str, Any] = {}
        if gt is not None: self.metadata["gt"] = gt
        if ge is not None: self.metadata["ge"] = ge
        if lt is not None: self.metadata["lt"] = lt
        if le is not None: self.metadata["le"] = le
        if min_length is not None: self.metadata["min_length"] = min_length
        if max_length is not None: self.metadata["max_length"] = max_length
        if pattern is not None: self.metadata["pattern"] = pattern
        self.examples = examples or []
